import React, { useState } from 'react';

const Booking = () => {
  const [isSearching, setIsSearching] = useState(false);

  const handleConfirm = () => {
    setIsSearching(true);
    // 3 second baad animation band karne ke liye
    setTimeout(() => {
      setIsSearching(false);
      alert("Driver Found! Toyota Glanza (DL 1CA 1234) is arriving in 5 mins.");
    }, 3000);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', backgroundColor: '#f4f7fe', position: 'relative' }}>
      
      {/* 1. Sidebar (Purana wala) */}
      <div style={{ width: '250px', backgroundColor: '#fff', borderRight: '1px solid #ddd', padding: '20px' }}>
        <h2 style={{ color: '#0052cc', fontWeight: 'bold' }}>Ucab</h2>
        <nav style={{ marginTop: '30px' }}>
          <div style={{ padding: '12px 0', cursor: 'pointer' }}>👤 Profile</div>
          <div style={{ padding: '12px 0', cursor: 'pointer', color: '#0052cc', fontWeight: 'bold' }}>🚗 My Rides</div>
          <div style={{ padding: '12px 0', cursor: 'pointer' }}>💳 Payments</div>
          <div style={{ padding: '12px 0', cursor: 'pointer' }}>⚙️ Support</div>
        </nav>
      </div>

      {/* 2. Main Content */}
      <div style={{ flex: 1, padding: '30px' }}>
        <header style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
          <h3 style={{ fontWeight: '600' }}>Cab Booking</h3>
          <div>🔔 <span style={{ backgroundColor: '#eee', padding: '8px 12px', borderRadius: '50%' }}>HV</span></div>
        </header>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.2fr', gap: '25px', height: '80%' }}>
          {/* Booking Form */}
          <div style={{ backgroundColor: '#fff', padding: '25px', borderRadius: '15px', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' }}>
            <h4 style={{ marginBottom: '20px', fontSize: '18px' }}>BOOK YOUR RIDE</h4>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ fontSize: '13px', color: '#666' }}>Pickup</label>
              <input type="text" placeholder="Enter pickup address..." style={{ width: '100%', padding: '12px', marginTop: '5px', borderRadius: '8px', border: '1px solid #ddd' }} />
            </div>
            <div style={{ marginBottom: '20px' }}>
              <label style={{ fontSize: '13px', color: '#666' }}>Drop-off</label>
              <input type="text" placeholder="Enter destination..." style={{ width: '100%', padding: '12px', marginTop: '5px', borderRadius: '8px', border: '1px solid #ddd' }} />
            </div>
            
            <h5 style={{ marginBottom: '15px' }}>Select Cab</h5>
            <div style={{ display: 'flex', gap: '15px', marginBottom: '25px' }}>
              <div style={{ border: '2px solid #0052cc', padding: '15px', borderRadius: '10px', textAlign: 'center', flex: 1, backgroundColor: '#f0f7ff' }}>
                🚕 <br/> <b>Ucab Mini</b> <br/> <small>$25</small>
              </div>
              <div style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '10px', textAlign: 'center', flex: 1 }}>
                🚙 <br/> <b>Ucab Sedan</b> <br/> <small>$35</small>
              </div>
            </div>

            <button 
              onClick={handleConfirm}
              style={{ width: '100%', padding: '16px', backgroundColor: '#28a745', color: '#fff', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold', fontSize: '16px' }}>
              CONFIRM BOOKING
            </button>
          </div>

          {/* Real Map Integration */}
          <div style={{ borderRadius: '15px', overflow: 'hidden', border: '1px solid #ddd' }}>
            <iframe 
              title="map"
              width="100%" 
              height="100%" 
              frameBorder="0" 
              src="https://www.openstreetmap.org/export/embed.html?bbox=77.00%2C28.40%2C77.30%2C28.70&layer=mapnik" 
            ></iframe>
          </div>
        </div>
      </div>

      {/* 3. Searching Loader Overlay */}
      {isSearching && (
        <div style={{ 
          position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', 
          backgroundColor: 'rgba(0,0,0,0.7)', display: 'flex', flexDirection: 'column',
          justifyContent: 'center', alignItems: 'center', zIndex: 1000, color: 'white'
        }}>
          <div style={{ 
            width: '50px', height: '50px', border: '5px solid #fff', 
            borderTop: '5px solid #0052cc', borderRadius: '50%', animation: 'spin 1s linear infinite' 
          }}></div>
          <h2 style={{ marginTop: '20px' }}>Searching for nearby drivers...</h2>
          <p>Finding you the best ride at lowest price</p>
          <style>{`
            @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
          `}</style>
        </div>
      )}

    </div>
  );
};

export default Booking;
